// src/app/roadmap/[id]/page.tsx
// Dynamic roadmap detail page — renders for each career position by ID.
// Uses Next.js App Router static generation via generateStaticParams.

import { notFound, redirect } from "next/navigation";
import { careerPositions, aiAutomationRoadmapPreview } from "@/data/careerRoadmaps";
import { RoadmapPhase } from "@/types/career";
import Header from "@/components/landing/Header";
import Footer from "@/components/landing/Footer";
import RoadmapHero from "@/components/roadmap/RoadmapHero";
import RoadmapPhaseList from "@/components/roadmap/RoadmapPhaseList";
import RoadmapSkills from "@/components/roadmap/RoadmapSkills";
import RoadmapCTA from "@/components/roadmap/RoadmapCTA";
import type { Metadata } from "next";

// ─── Static params — pre-render a page for every career position ────────────
export function generateStaticParams() {
  return careerPositions.map((position) => ({ id: position.id }));
}

// ─── Dynamic metadata per roadmap ──────────────────────────────────────────
export async function generateMetadata({
  params,
}: {
  params: Promise<{ id: string }>;
}): Promise<Metadata> {
  const { id } = await params;
  const position = careerPositions.find((p) => p.id === id);
  if (!position) return { title: "Roadmap Not Found" };

  return {
    title: `${position.title} Roadmap — AI Career Roadmaps`,
    description: position.description,
  };
}

// ─── Roadmap phases per position ───────────────────────────────────────────
// For MVP, only the AI Automation Specialist has full phase data.
// All other positions fall back to a coming-soon placeholder set.

const comingSoonPhases: RoadmapPhase[] = [
  {
    phaseNumber: 1,
    title: "Foundations",
    explanation: "Core concepts and fundamentals for this career path. Full content coming soon.",
    access: "free",
  },
  {
    phaseNumber: 2,
    title: "Core Skills",
    explanation: "Hands-on skill building with the most important tools and techniques.",
    access: "locked",
  },
  {
    phaseNumber: 3,
    title: "Advanced Practice",
    explanation: "Real-world projects and advanced techniques to deepen your expertise.",
    access: "locked",
  },
  {
    phaseNumber: 4,
    title: "Portfolio Projects",
    explanation: "Build portfolio-ready projects you can show to clients or employers.",
    access: "locked",
  },
];

function getPhasesForPosition(id: string): RoadmapPhase[] {
  if (id === "ai-automation-specialist") return aiAutomationRoadmapPreview;
  return comingSoonPhases;
}

// ─── Page component ─────────────────────────────────────────────────────────
export default async function RoadmapPage({
  params,
}: {
  params: Promise<{ id: string }>;
}) {
  const { id } = await params;
  const position = careerPositions.find((p) => p.id === id);

  if (!position) notFound();

  redirect(`/roadmaps/${id}`);

  const phases = getPhasesForPosition(id);

  return (
    <>
      <Header />
      <main>
        <RoadmapHero position={position} />
        <RoadmapPhaseList phases={phases} />
        <RoadmapSkills skills={position.keySkills} />
        <RoadmapCTA status={position.status} title={position.title} />
      </main>
      <Footer />
    </>
  );
}
